#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[1005];
        scanf("%s", s);
        for (int i = 0; s[i] != '\0'; ++i) {
            if ((s[i] >= 'a' && s[i] <= 'z') || (s[i] >= 'A' && s[i] <= 'Z'))
                printf("%c", s[i]);
        }
        printf("\n");
    }
    return 0;
}

