const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const T = parseInt(lines[i++], 10);
let results = [];
for (let t = 0; t < T; ++t) {
  const s = lines[i++];
  let res = '';
  for (const ch of s) {
    if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')) {
      res += ch;
    }
  }
  results.push(res);
}
process.stdout.write(results.join('\n'));
